/* Two Sum */
def two_sum(nums, target):
    seen = {}
    for i, v in enumerate(nums):
        if target - v in seen:
            return [seen[target-v], i]
        seen[v] = i
    return None

/* Reverse linked list (iterativo) */
class ListNode:
    def __init__(self, val=0, nxt=None):
        self.val = val
        self.next = nxt

def reverse_list(head):
    prev = None
    curr = head
    while curr:
        nxt = curr.next
        curr.next = prev
        prev = curr
        curr = nxt
    return prev

/* Binary search (template) */
def binary_search(arr, target):
    lo, hi = 0, len(arr) - 1
    while lo <= hi:
        mid = (lo + hi) // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            lo = mid + 1
        else:
            hi = mid - 1
    return -1

/* Sliding window (longest substring without repeats) */
def longest_unique_substring(s):
    seen = {}
    start = 0
    best = 0
    for i, ch in enumerate(s):
        if ch in seen and seen[ch] >= start:
            start = seen[ch] + 1
        seen[ch] = i
        best = max(best, i - start + 1)
    return best

/* DFS recursion (tree) */
def dfs(node):
    if not node: return
    # preorder: process node
    dfs(node.left)
    dfs(node.right)

/* BFS (graph shortest path unweighted) */
from collections import deque
def bfs_shortest(start, target, neighbors):
    q = deque([(start, 0)])
    seen = {start}
    while q:
        node, dist = q.popleft()
        if node == target:
            return dist
        for nb in neighbors(node):
            if nb not in seen:
                seen.add(nb)
                q.append((nb, dist+1))
    return -1

